INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES(359, 59, 'mid_banner_description', 'We are a young and passionate experiential advertising team focused on creating immersive brand experiences. We combine creativity, technology, and execution to help brands connect with audiences in meaningful, real-world ways.');
